def _extract_channel_samples(preset_text, channel_name):
    pattern = rf"\(channel\s+{re.escape(channel_name)}\)[\s\S]*?\(samples\s+256\s+([\d\.\sEe+-]+)\)"
    m = re.search(pattern, preset_text)
    if not m:
        print("WARNING!! Missing preset samples for " + channel_name + " , returning identity ramp instead")
        nums = [i / 256 for i in range(256)]
    else:     
        nums = [float(x) for x in m.group(1).split()]

    if len(nums) != 256:
        raise ValueError(f"{channel_name} samples count != 256")
    arr = np.array(nums, dtype=np.float64)
    lut = np.clip(np.round(arr * 255.0), 0, 255).astype(np.uint8)
    return lut

def soft_clip_value_curve(input_lut, shadows_threshold=30, highlights_threshold=225):
    """
    Modifies an existing value LUT to soft-clip extremes
    """
    output_lut = input_lut.copy()
    
    # Compress dark regions (below shadows_threshold)
    dark_mask = np.arange(256) < shadows_threshold
    dark_vals = np.arange(256)[dark_mask]
    # Map 0->shadows_threshold to shadows_threshold/2->shadows_threshold
    output_lut[dark_mask] = (shadows_threshold / 2 + 
                             (dark_vals / shadows_threshold) * (shadows_threshold / 2))
    
    # Compress bright regions (above highlights_threshold)
    bright_mask = np.arange(256) > highlights_threshold
    bright_vals = np.arange(256)[bright_mask]
    remaining = 255 - highlights_threshold
    # Soft compress the top range
    normalized = (bright_vals - highlights_threshold) / remaining
    output_lut[bright_mask] = highlights_threshold + remaining * (normalized ** 0.7)
    
    return output_lut.astype(np.uint8)

value_lut = _extract_channel_samples(GIMP_CURVES_PRESET, "value")
value_lut = soft_clip_value_curve(value_lut, shadows_threshold=20, highlights_threshold=150)

red_lut   = _extract_channel_samples(GIMP_CURVES_PRESET, "red")
green_lut = _extract_channel_samples(GIMP_CURVES_PRESET, "green")
blue_lut  = _extract_channel_samples(GIMP_CURVES_PRESET, "blue")


