for row in range(rows):
    for col in range(cols):
        tile_pil = dz.get_tile(level, (col, row))
        if tile_pil.mode == "RGBA":
            tile_pil = tile_pil.convert("RGB")

        tile_np = np.array(tile_pil) 
        tile_bgr = cv2.cvtColor(tile_np, cv2.COLOR_RGB2BGR)

        b, g, r = cv2.split(tile_bgr)
        b, g, r = [cv2.LUT(channel, value_lut) for channel in (b, g, r)]

        b = cv2.LUT(b, blue_lut)
        g = cv2.LUT(g, green_lut)
        r = cv2.LUT(r, red_lut)

        tile_proc = cv2.merge([b, g, r])

        x0 = col * tile_size
        y0 = row * tile_size

        h, w = tile_proc.shape[:2]
        tile_rgb = cv2.cvtColor(tile_proc, cv2.COLOR_BGR2RGB)

        mosaic[y0:y0+h, x0:x0+w, :] = tile_rgb

