######################## shadows + highlights ########################
# Convert to LAB color space: separates L (lightness) from a/b (color)
def apply_shadows_highlights(
    img_rgb_uint8,
    shadow=0,       # [-100..100] positive -> lift shadows, negative -> deepen
    highlight=0,    # [-100..100] positive -> brighten highs, negative -> compress highs
    ts=0.40,        # shadow threshold (0..1)
    th=0.60,        # highlight threshold (0..1)
    width=0.25,     # transition softness
    gamma_s=2.0,    # shadow gamma
    gamma_h=2.0     # highlight gamma
):
    """
    LAB-based shadows/highlights. Operates on L only, preserves color.
    img_rgb_uint8: HxWx3, uint8 RGB
    Returns: HxWx3 uint8 RGB
    """
    def smoothstep(edge0, edge1, x):
        t = np.clip((x - edge0) / max(1e-6, (edge1 - edge0)), 0.0, 1.0)
        return t * t * (3.0 - 2.0 * t)

    # 1) to LAB
    lab  = cv2.cvtColor(img_rgb_uint8, cv2.COLOR_RGB2LAB)
    L, A, B = cv2.split(lab)
    Lf = (L.astype(np.float32) / 255.0)

    # only adjust highlights if their mean is too bright or too dark
    hi_mask = Lf >= th
    if np.any(hi_mask):
        hi_mean = float(Lf[hi_mask].mean())
        if 0.3 <= hi_mean <= 0.85:
            highlight = 0

    # 2) soft masks
    ws = 1.0 - smoothstep(ts, ts + width, Lf)       # shadows mask
    wh = smoothstep(th - width, th, Lf)             # highlights mask

    # 3) deltas
    s_amt = np.clip(shadow / 100.0, -1.0, 1.0)
    h_amt = np.clip(highlight / 100.0, -1.0, 1.0)

    s_delta_bright = np.power(Lf, 1.0 / max(1e-6, gamma_s)) - Lf
    s_delta_darken = np.power(Lf,        max(1e-6, gamma_s)) - Lf
    Lf = Lf + ws * np.where(s_amt >= 0.0, s_amt * s_delta_bright, (-s_amt) * s_delta_darken)

    h_delta_bright = np.power(Lf, 1.0 / max(1e-6, gamma_h)) - Lf
    h_delta_darken = np.power(Lf,        max(1e-6, gamma_h)) - Lf
    Lf = Lf + wh * np.where(h_amt >= 0.0, h_amt * h_delta_bright, (-h_amt) * h_delta_darken)

    # 4) back to RGB
    L_adj = np.clip(Lf * 255.0, 0, 255).astype(np.uint8)
    lab_adj = cv2.merge([L_adj, A, B])
    out_rgb = cv2.cvtColor(lab_adj, cv2.COLOR_LAB2RGB)
    return out_rgb


######################## sharpen ########################
def unsharp_mask(img, radius=1.0, amount=0.5, threshold=0):
    """
    Apply unsharp mask sharpening
    
    Parameters:
    - radius: Gaussian blur radius (pixels) - matches GIMP radius
    - amount: Sharpening strength (0-2+) - matches GIMP amount
    - threshold: Minimum brightness change to sharpen (0-255) - matches GIMP threshold
    """
    # Convert radius to sigma for Gaussian blur
    sigma = radius
    
    # Create blurred version
    blurred = cv2.GaussianBlur(img, (0, 0), sigma)
    
    # Calculate sharpened image
    sharpened = cv2.addWeighted(img, 1.0 + amount, blurred, -amount, 0)
    
    # Apply threshold if specified
    if threshold > 0:
        low_contrast_mask = np.absolute(img - blurred) < threshold
        sharpened = np.where(low_contrast_mask, img, sharpened)
    
    return sharpened

